--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1065,6 +1065,21 @@ static Value *foldUnsignedUnderflowCheck(ICmpInst *ZeroICmp,
                                          InstCombiner::BuilderTy &Builder) {
   Value *ZeroCmpOp;
   ICmpInst::Predicate EqPred;
+
+  // Handle the pattern: (icmp ne X, -1) & (icmp ule (X + C), Y)
+  // This checks that X is not max unsigned (so X+C does not overflow) and
+  // X+C <= Y. If C == 1, this is equivalent to X < Y (unsigned).
+  Value *X, *Y;
+  ICmpInst::Predicate UnsignedPred;
+  if (IsAnd &&
+      match(ZeroICmp, m_ICmp(EqPred, m_Value(X), m_AllOnes())) &&
+      EqPred == ICmpInst::ICMP_NE &&
+      match(UnsignedICmp,
+            m_ICmp(UnsignedPred, m_Add(m_Specific(X), m_One()), m_Value(Y))) &&
+      UnsignedPred == ICmpInst::ICMP_ULE &&
+      (ZeroICmp->hasOneUse() || UnsignedICmp->hasOneUse())) {
+    return Builder.CreateICmpULT(X, Y);
+  }
   if (!match(ZeroICmp, m_ICmp(EqPred, m_Value(ZeroCmpOp), m_Zero())) ||
       !ICmpInst::isEquality(EqPred))
     return nullptr;
@@ -1073,8 +1088,6 @@ static Value *foldUnsignedUnderflowCheck(ICmpInst *ZeroICmp,
     return isKnownNonZero(V, Q.DL, /*Depth=*/0, Q.AC, Q.CxtI, Q.DT);
   };

-  ICmpInst::Predicate UnsignedPred;
-
   Value *A, *B;
   if (match(UnsignedICmp,
             m_c_ICmp(UnsignedPred, m_Specific(ZeroCmpOp), m_Value(A))) &&
@@ -3099,13 +3112,10 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
   if (Value *V = foldPowerOf2AndShiftedMask(LHS, RHS, IsAnd, Builder))
     return V;

-  // TODO: Verify whether this is safe for logical and/or.
-  if (!IsLogical) {
-    if (Value *X = foldUnsignedUnderflowCheck(LHS, RHS, IsAnd, Q, Builder))
-      return X;
-    if (Value *X = foldUnsignedUnderflowCheck(RHS, LHS, IsAnd, Q, Builder))
-      return X;
-  }
+  if (Value *X = foldUnsignedUnderflowCheck(LHS, RHS, IsAnd, Q, Builder))
+    return X;
+  if (Value *X = foldUnsignedUnderflowCheck(RHS, LHS, IsAnd, Q, Builder))
+    return X;

   if (Value *X = foldEqOfParts(LHS, RHS, IsAnd))
     return X;

